// Initial implementation of OAuth 2.0 implicit flow client in JavaScript

// Function to parse access token from URL fragment
function parseAccessToken() {
    const urlParams = new URLSearchParams(window.location.hash.substring(1));
    return urlParams.get('access_token');
}

// Function to store the access token for the session duration
function storeAccessToken(token) {
    sessionStorage.setItem('accessToken', token);
}

// Function to retrieve the access token from storage
function getAccessToken() {
    return sessionStorage.getItem('accessToken');
}

// Function to make API calls using the access token
async function fetchApi(url, options = {}) {
    const token = getAccessToken();
    if (token) {
        options.headers = {
            ...options.headers,
            Authorization: `Bearer ${token}`
        };
    }
    try {
        const response = await fetch(url, options);
        return await response.json();
    } catch (error) {
        console.error('API call failed:', error);
        throw error;
    }
}

// Main function to handle OAuth flow
async function handleOAuthFlow() {
    const token = parseAccessToken();
    if (token) {
        storeAccessToken(token);
        // Use the token for API calls
        try {
            const data = await fetchApi('https://api.example.com/data');
            console.log('API response:', data);
        } catch (error) {
            console.error('Failed to fetch data:', error);
        }
    } else {
        console.warn('No access token found in URL fragment.');
    }
}

// Call the main function on page load
window.onload = handleOAuthFlow;